def run_crystal_discovery(state, crystal_memory, batch_size=10, save_interval=180):
    import time, random, traceback, json

    print(f"Crystal memory: {len(crystal_memory.crystals)} existing crystals")
    print(f"Queue: {len(state.concept_queue)} concepts")
    es = state.evolution_stats
    print(f"Evolution stats: L1:{es.get(1,0)} L2:{es.get(2,0)} L3:{es.get(3,0)} L4:{es.get(4,0)}")
    print("Press Ctrl+C to stop")
    print("=" * 45)

    batch_count = 0
    last_save = time.time()
    queue_file = "concept_queue.json"

    # Load saved queue
    try:
        with open(queue_file, "r") as f:
            saved_queue = json.load(f)
        if saved_queue:
            state.concept_queue = saved_queue
    except Exception:
        pass

    try:
        while state.concept_queue:
            concept = state.concept_queue.pop(0)

            if concept in state.processed_concepts or concept in state.failed_concepts:
                continue

            batch_count += 1
            print(f"\n[{batch_count}] Processing: {concept}")

            try:
                success = process_concept_to_crystal(concept, state, crystal_memory)
            except Exception as e:
                print(f"    Exception processing {concept}: {e}")
                traceback.print_exc()
                success = False

            if success:
                state.processed_concepts.add(concept)
                state.total_harvested += 1
            else:
                state.failed_concepts.add(concept)
                print(f"    Failed to create crystal for: {concept}")

            if batch_count % batch_size == 0 or time.time() - last_save > save_interval:
                print(f"Progress: {batch_count} processed")
                save_state(state)
                try:
                    with open(queue_file, "w") as f:
                        json.dump(state.concept_queue, f)
                except Exception:
                    pass
                last_save = time.time()

            time.sleep(random.uniform(1.5, 3.0))

    except KeyboardInterrupt:
        print("\nStopped by user")
    except Exception:
        traceback.print_exc()
    finally:
        save_state(state)
        try:
            with open(queue_file, "w") as f:
                json.dump(state.concept_queue, f)
        except Exception:
            pass
        print("Final report")  # Replace with your final report logic
